def solve(packet: str) -> float:
    """Parse a packet and return the sum of token values normalized by the channel.

    Packet format: "channel:token1,token2,...,tokenN"
    Valid tokens: letter A-G followed by a single digit (e.g., "A3", "B7")
    Channels: "alpha" (divide by 100), "beta" (divide by 10), others (no normalization)
    """
    if not packet or ':' not in packet:
        return -1.0

    parts = packet.split(':', 1)
    if len(parts) != 2:
        return -1.0

    channel = parts[0].strip()
    tokens_str = parts[1].strip()

    if not tokens_str:
        return -1.0

    tokens = tokens_str.split(',')

    total = 0
    for token in tokens:
        token = token.strip()
        if len(token) != 2 or token[0] not in "ABCDEFG" or not token[1].isdigit():
            return -1.0
        total += int(token[1])

    if channel == "alpha":
        return total / 100.0
    elif channel == "beta":
        return total / 10.0
    else:
        return float(total)
