    """Find the valid alpha/beta packet with the highest token-sum score."""
    import re

    def parse_packet(packet):
        """Parse a fluxon packet string into components."""
        # Expected format: "TYPE:PAYLOAD:VER:CHECKSUM" or similar
        # Let's try to parse based on common patterns
        if not isinstance(packet, str):
            return None

        # Try splitting by colon
        parts = packet.split(':')
        if len(parts) >= 4:
            ptype = parts[0]
            payload = parts[1]
            ver = parts[2]
            checksum = parts[3]
            return {'type': ptype, 'payload': payload, 'ver': ver, 'checksum': checksum}
        return None

    def compute_checksum(payload, ver):
        """Compute checksum for a payload and version."""
        # Simple checksum: sum of character codes modulo some value
        if not payload:
            return 0
        return sum(ord(c) for c in payload) % 256

    def is_valid_packet(record):
        """Check if a packet record is valid."""
        if record is None:
