def solve(frames: list[str]) -> dict[str, float]:
    """Per channel, average the normalized token sums of valid framed packets."""
    from collections import defaultdict

    channel_sums = defaultdict(float)
    channel_counts = defaultdict(int)

    for frame in frames:
        # Validate frame format: must start with [ and end with ]
        if not (frame.startswith("[") and frame.endswith("]")):
            continue

        # Strip brackets
        content = frame[1:-1]

        # Parse the content - expected format: "channel:token1,token2,..."
        if ":" not in content:
            continue

        parts = content.split(":", 1)
        if len(parts) != 2:
            continue

        channel = parts[0].strip()
        tokens_str = parts[1].strip()

        if not channel or not tokens_str:
            continue

        # Parse tokens
        tokens = tokens_str.split(",")

        token_sum = 0.0
        valid = True
        for token in tokens:
            token = token.strip()
            if not token:
                valid = False
                break
            try:
                value = float(token)
            except ValueError:
                valid = False
                break
            token_sum += value

        if not valid:
            continue

        # Normalize the token sum based on channel
        normalized = normalize_channel_value(channel, token_sum)

        channel_sums[channel] += normalized
        channel_counts[channel] += 1

    result = {}
    for channel in channel_sums:
        if channel_counts[channel] > 0:
            result[channel] = channel_sums[channel] / channel_counts[channel]

    return result


