from typing import Any

def solve(subject: str, resource: str, action: str, policies: list[str]) -> bool:
    """Decide whether the action is allowed based on the given policies."""
    for policy in policies:
        if _evaluate_policy(policy, subject, resource, action):
            return True
    return False


def _evaluate_policy(policy: str, subject: str, resource: str, action: str) -> bool:
    """Evaluate a single policy string against the given subject, resource, and action."""
    policy = policy.strip()
    if not policy:
        return False

    # Parse the policy. Expected format:
    # "subject, resource, action" or "subject,resource,action"
    # with optional wildcards "*"
    parts = [p.strip() for p in policy.split(",")]
    if len(parts) != 3:
        return False

    subj_part, res_part, act_part = parts

    if not _match(subj_part, subject):
        return False
    if not _match(res_part, resource):
        return False
    if not _match(act_part, action):
        return False

    return True


def _match(pattern: str, value: str) -> bool:
    """Match a value against a pattern. '*' matches everything."""
    if pattern == "*":
        return True
    return pattern == value
