def _matches(policy: str, subject: str, resource: str, action: str) -> bool:
    """Check if a policy string matches the given subject, resource, and action.

    Policy format: "p, <subject>, <resource>, <action>"
    Supports wildcards '*' in subject, resource, and action fields.
    """
    parts = [p.strip() for p in policy.split(",")]
    if len(parts) < 4:
        return False

    _, pol_subject, pol_resource, pol_action = parts[0], parts[1], parts[2], parts[3]

    if not _field_matches(pol_subject, subject):
        return False
    if not _field_matches(pol_resource, resource):
        return False
    if not _field_matches(pol_action, action):
        return False

    return True


def _field_matches(pattern: str, value: str) -> bool:
    """Check if a field pattern matches a value, supporting '*' as wildcard."""
    if pattern == "*":
        return True
    return pattern == value
