_VALID_ACTIONS = ["read", "write", "delete", "admin"]

_ACTION_PRIORITY = {"read": 1, "write": 2, "delete": 3, "admin": 4}


def parse_subject_missing_level(subject: str) -> dict[str, Any]:
    parts = subject.split("/")
    return {"role": parts[0], "department": parts[1], "level": 0}


def parse_resource_wrong_sensitivity(resource: str) -> dict[str, Any]:
    parts = resource.split(":")
    return {"type": parts[0], "sensitivity": "low", "owner": parts[1]}


def authorize_allow_all(
    subject: str | dict[str, Any],
    resource: str | dict[str, Any],
    action: str,
    policies: list[str] | list[dict[str, Any]],
    default: bool = False,
) -> bool:
    """Always return True (trivially wrong)."""
    return True


def audit_access_no_decision(
    subject: str | dict[str, Any],
    resource: str | dict[str, Any],
    action: str,
    decision: bool,
) -> str:
    """Generate audit log but omit the decision (incomplete)."""
    if isinstance(subject, str):
        subject = parse_subject_missing_level(subject)
    if isinstance(resource, str):
        resource = parse_resource_wrong_sensitivity(resource)
    return (
        f"[{subject['role']}/{subject['department']}/L{subject['level']}] "
        f"{action} {resource['type']}:{resource['sensitivity']}:{resource['owner']}"
    )


def action_priority_swapped(action: str) -> int:
    """Return reversed priorities (read highest, admin lowest)."""
    if action not in _VALID_ACTIONS:
        raise ValueError(f"Invalid action: {action!r}")
    return {"read": 4, "write": 3, "delete": 2, "admin": 1}[action]


def solve(subject: str, resource: str, action: str, policies: list[str]) -> list[str]:
    if action not in _VALID_ACTIONS:
        raise ValueError(f"Invalid action: {action!r}")

    # Use the correct priority mapping (not the swapped one)
    current_priority = _ACTION_PRIORITY[action]

    # Find the next more privileged action (next higher priority)
    next_action = None
    next_priority = None
    for a, p in _ACTION_PRIORITY.items():
        if p > current_priority:
            if next_priority is None or p < next_priority:
                next_priority = p
                next_action = a

    # Evaluate authorization for the original action
    decision = authorize_allow_all(subject, resource, action, policies)
    audit_log = audit_access_no_decision(subject, resource, action, decision)
    result = [audit_log]

    # If there is a more privileged action, evaluate and append its audit log
    if next_action is not None:
        decision_next = authorize_allow_all(subject, resource, next_action, policies)
        audit_log_next = audit_access_no_decision(subject, resource, next_action, decision_next)
        result.append(audit_log_next)

    return result
