            p_role, p_dept, p_min_level, p_action = policy_parts
            p_min_level = int(p_min_level)
        elif isinstance(policy, dict):
            p_role = policy.get("role", "*")
            p_dept = policy.get("department", "*")
            p_min_level = policy.get("min_level", 0)
            p_action = policy.get("action", "*")
        else:
