from typing import Any

def solve(subjects: list[str], resource: str, policies: list[str]) -> str | None:
    # Parse policies into a list of dicts
    parsed_policies = []
    for p in policies:
        parts = p.strip().split()
        if len(parts) >= 4 and parts[2] == "allow":
            # Format: "subject resource action allow" or similar
            parsed_policies.append({
                "subject": parts[0],
                "resource": parts[1],
                "action": parts[3] if len(parts) > 3 else parts[2],
            })

    # Determine allowed actions per subject
    subject_actions = {}
    for subject in subjects:
        actions = set()
        for policy in parsed_policies:
            if policy["subject"] == subject and policy["resource"] == resource:
                actions.add(policy["action"])
        subject_actions[subject] = actions

    # Find the subject with the most distinct actions
    best_subject = None
    best_count = 0
    for subject in subjects:
        count = len(subject_actions[subject])
        if count > best_count:
            best_count = count
            best_subject = subject

    return best_subject if best_count > 0 else None
