from typing import Any


def solve(subject: str, resources: list[str], policies: list[str]) -> dict[str, list[str]]:
    """Return a dictionary mapping each resource string to the list of actions that the subject is allowed to perform on it."""
    # Parse policies to determine allowed actions per resource
    # Each policy string is expected to be in a format like:
    # "subject:resource:action" or similar IAM-like policy format

    result: dict[str, list[str]] = {resource: [] for resource in resources}

    for policy in policies:
        policy = policy.strip()
        if not policy:
            continue

        # Try to parse the policy
        # Common formats: "subject:resource:action", "subject:resource:action:effect", etc.
        parts = policy.split(":")

        if len(parts) >= 3:
            policy_subject = parts[0].strip()
            policy_resource = parts[1].strip()
            policy_action = parts[2].strip()

            # Check if this policy applies to our subject
            if policy_subject == "*" or policy_subject == subject:
                # Check if the resource is in our resources list
                if policy_resource == "*" or policy_resource in resources:
                    # Determine which resources this applies to
                    if policy_resource == "*":
                        applicable_resources = resources
                    else:
                        applicable_resources = [policy_resource]

                    for res in applicable_resources:
                        if res in result:
                            if policy_action == "*":
                                # Wildcard action - all actions allowed
                                if not result[res]:
                                    result[res] = ["*"]
                            else:
                                if "*" not in result[res] and policy_action not in result[res]:
                                    result[res].append(policy_action)

    return result
