    def parse_series(s: str) -> dict[str, Any]:
        """Parse a series string of format 'ts1:val1,ts2:val2,...' into a dict."""
        timestamps = []
        values = []
        if s.strip():
            for pair in s.split(","):
                pair = pair.strip()
                if not pair:
                    continue
                ts_str, val_str = pair.split(":")
                timestamps.append(int(ts_str.strip()))
                values.append(float(val_str.strip()))
