        merged: dict[int, float] = {}
        for ts, value in zip(s2["timestamps"], s2["values"]):
            merged[ts] = value
        for ts, value in zip(s1["timestamps"], s1["values"]):
            merged[ts] = value
        sorted_ts = sorted(merged)
        return {"timestamps": sorted_ts, "values": [merged[ts] for ts in sorted_ts]}

    def normalize_minmax(series: dict[str, Any]) -> list[float]:
        """Apply min-max scaling: (v - min) / (max - min)."""
