def solve(series: str, factor: float) -> str:
    """Parse the series, scale every value by factor, and format the result as a Nimbla series string."""
    # Parse the series string to extract values
    # Expected format: something like "series_name: [v1, v2, v3]" or just "[v1, v2, v3]"
    import re

    # Try to find a list of numbers in the series string
    match = re.search(r'\[([^\]]*)\]', series)
    if match:
        values_str = match.group(1)
        # Parse individual values
        values = []
        for v in values_str.split(','):
            v = v.strip()
            if v:
                try:
                    values.append(float(v))
                except ValueError:
                    continue
    else:
        # Try to parse space-separated or comma-separated values
        values = []
        for v in series.replace(',', ' ').split():
            try:
                values.append(float(v))
            except ValueError:
                continue

    # Scale every value by factor
    scaled_values = [v * factor for v in values]

    # Format as Nimbla series string
    formatted_values = ', '.join(str(v) for v in scaled_values)
    return f"[{formatted_values}]"
