def solve(series_list: list[str]) -> dict:
    def parse_series(s: str) -> dict[str, Any]:
        """Parse a series string into a dict with 'timestamps' and 'values'."""
        lines = s.strip().split("\n")
        timestamps = []
        values = []
        for line in lines:
            line = line.strip()
            if not line:
                continue
            parts = line.split()
            if len(parts) == 2:
                ts = int(parts[0])
                val = float(parts[1])
                timestamps.append(ts)
                values.append(val)
        return {"timestamps": timestamps, "values": values}

    def merge_all_series(series_dicts: list[dict[str, Any]]) -> dict[str, Any]:
        """Merge all series; later series in the list win on timestamp conflicts."""
        merged: dict[int, float] = {}
        for sd in series_dicts:
            for ts, value in zip(sd["timestamps"], sd["values"]):
                merged[ts] = value
        sorted_ts = sorted(merged)
        return {"timestamps": sorted_ts, "values": [merged[ts] for ts in sorted_ts]}

    def compute_summary(series: dict[str, Any]) -> dict[str, Any]:
        """Compute full statistical summary of a series."""
        values = series["values"]
        n = len(values)
        if n == 0:
            return {
                "count": 0,
                "min": 0.0,
                "max": 0.0,
                "mean": 0.0,
                "std": 0.0,
            }
        min_val = min(values)
        max_val = max(values)
        mean_val = sum(values) / n
        if n > 1:
            variance = sum((v - mean_val) ** 2 for v in values) / n
            std_val = math.sqrt(variance)
        else:
            std_val = 0.0
        return {
            "count": n,
            "min": min_val,
            "max": max_val,
            "mean": mean_val,
            "std": std_val,
        }

