def parse_series(series_str: str) -> dict[str, Any]:
    """Parse a series string into a dict with 'timestamps' and 'values'."""
    parts = series_str.strip().split()
    n = int(parts[0])
    timestamps = []
    values = []
    for i in range(n):
        ts = int(parts[1 + 2 * i])
        val = float(parts[1 + 2 * i + 1])
        timestamps.append(ts)
        values.append(val)
    return {"timestamps": timestamps, "values": values}


def solve(series_list: list[str]) -> int:
    # Parse all series
    parsed = [parse_series(s) for s in series_list]

    # Collect all timestamps across all series
    all_timestamps = []
    for p in parsed:
        all_timestamps.extend(p["timestamps"])

    if not all_timestamps:
        return 0

    # Determine global minimum and median timestamp
    sorted_all = sorted(all_timestamps)
    global_min = sorted_all[0]
    n_total = len(sorted_all)
    if n_total % 2 == 0:
        median = sorted_all[n_total // 2 - 1]
    else:
        median = sorted_all[n_total // 2]

    # Select entries in the lower half [global_min, median]
    sub_series = []
    for p in parsed:
        ts_list = p["timestamps"]
        val_list = p["values"]
        new_ts = []
        new_vals = []
        for ts, val in zip(ts_list, val_list):
            if global_min <= ts <= median:
                new_ts.append(ts)
                new_vals.append(val)
        if new_ts:
            sub_series.append({"timestamps": new_ts, "values": new_vals})

    # Merge all sub-series
    if not sub_series:
        return 0

    merged = sub_series[0]
    for i in range(1, len(sub_series)):
        merged = merge_nimbla_series_first_wins(merged, sub_series[i])

    return len(merged["timestamps"])
