def solve(series_list: list[str], factor: float) -> list[float]:
    # Parse each series
    parsed_series = []
    for s in series_list:
        parts = s.split()
        timestamps = []
        values = []
        for i in range(0, len(parts), 2):
            timestamps.append(int(parts[i]))
            values.append(float(parts[i + 1]))
        parsed_series.append({"timestamps": timestamps, "values": values})

    # Merge all series (first series wins on timestamp conflicts)
    merged: dict[int, float] = {}
    for series in reversed(parsed_series):
        for ts, value in zip(series["timestamps"], series["values"]):
            merged[ts] = value

    sorted_ts = sorted(merged)
    merged_values = [merged[ts] * factor for ts in sorted_ts]

    # Apply min-max normalization
    if not merged_values:
        return []
    min_v = min(merged_values)
    max_v = max(merged_values)
    if max_v == min_v:
        return [0.0] * len(merged_values)
    return [(v - min_v) / (max_v - min_v) for v in merged_values]
